const reviewSlidesHtml = reviews
  .map((review, index) => {
    const stars = "★".repeat(Math.max(0, Math.min(5, review.rating)));
    const sampleLabel = review.isSample ? "Sample Feedback" : "Client Feedback";
    return `<div class="reviews-slide" data-review-slide data-review-id="${review.id}" role="group" aria-roledescription="slide" aria-label="Review ${index + 1} of ${reviews.length}">
      <article class="review-card" data-review-status="${review.isSample ? "placeholder" : "approved"}">
        <span class="review-quote" aria-hidden="true">“</span>
        <div class="review-card-top">
          <span class="review-sample-label">${sampleLabel}</span>
          <div class="review-stars" aria-label="${review.rating} out of 5 stars — sample rating layout"><span aria-hidden="true">${stars}</span></div>
        </div>
        ${review.service ? `<span class="review-service">${review.service}</span>` : ""}
        <blockquote><p>“${review.message}”</p></blockquote>
        <footer class="review-person">
          <span class="review-avatar" aria-hidden="true">${review.initials}</span>
          <span><strong>${review.name}</strong><small>${review.businessType}</small></span>
        </footer>
      </article>
    </div>`;
  })
  .join("");

